5	//! VVC Commit - Core commit infrastructure
6	//!
7	//! Provides atomic commit workflow: lock, stage, guard, commit.
8	//! Used by vvx commit and JJK commands for consistent commit handling.
9	//!
10	//! ## Usage Patterns
11	//!
12	//! ### Simple commit (lock acquired and released automatically):
13	//! ```ignore
14	//! let exit_code = vvc::commit(&args);
15	//! ```
16	//!
17	//! ### Protected operation (hold lock across multiple steps):
18	//! ```ignore
19	//! let lock = vvc::vvcc_CommitLock::vvcc_acquire()?;
20	//! // ... do work while holding lock ...
21	//! let hash = lock.vvcc_commit(&args)?;
22	//! // lock released when dropped
23	//! ```
24	//!
25	//! Exit codes:
26	//!   0 - Success (commit hash printed to stdout)
27	//!   1 - Failure (lock held, guard failed, claude failed, commit failed)
28	
29	use crate::vvcg_guard;
30	use crate::vvco_output::vvco_Output;
31	use crate::{vvco_out, vvco_err};
32	
33	/// Lock reference path for commit operations
34	const VVCC_LOCK_REF: &str = "refs/vvg/locks/vvx";
35	
36	/// Arguments for commit operation
37	///
38	/// Note: No Default impl - callers must explicitly specify all fields,
39	/// including size limits. Use VVCG_SIZE_LIMIT/VVCG_WARN_LIMIT constants
40	/// for standard behavior.
41	#[derive(Debug, Clone)]
42	pub struct vvcc_CommitArgs {
43	    /// Prefix string to prepend to commit message (e.g., "[jj:BRAND][F00/silks]")
44	    pub prefix: Option<String>,
45	    /// Commit message; if absent, invoke claude to generate from diff
46	    pub message: Option<String>,
47	    /// Allow empty commits (for chalk markers)
48	    pub allow_empty: bool,
49	    /// Skip 'git add -A' (respect pre-staged files)
50	    pub no_stage: bool,
51	    /// Size limit in bytes (use VVCG_SIZE_LIMIT for standard behavior)
52	    pub size_limit: u64,
53	    /// Warning threshold in bytes (use VVCG_WARN_LIMIT for standard behavior)
54	    pub warn_limit: u64,
55	}
56	
57	/// RAII guard that holds the commit lock.
58	///
59	/// The lock is automatically released when the guard is dropped, ensuring
60	/// no code path can leak the lock. Use this when you need to hold the lock
61	/// across multiple operations (e.g., modify gallops, then commit).
62	///
63	/// ## Example
64	/// ```ignore
65	/// let lock = vvcc_CommitLock::vvcc_acquire()?;
66	/// // Do protected work here...
67	/// let hash = lock.vvcc_commit(&args)?;
68	/// // Lock released when `lock` goes out of scope
69	/// ```
70	pub struct vvcc_CommitLock {
71	    /// Private field prevents external construction
72	    _private: (),
73	}
74	
75	impl vvcc_CommitLock {
76	    /// Acquire the commit lock.
77	    ///
78	    /// Returns `Err` if the lock is already held by another operation.
79	    /// The lock is held until this `vvcc_CommitLock` is dropped.
80	    pub fn vvcc_acquire() -> Result<Self, String> {
81	        zvvcc_acquire_lock()?;
82	        Ok(vvcc_CommitLock { _private: () })
83	    }
84	
85	    /// Perform a commit while holding the lock.
86	    ///
87	    /// This does NOT release the lock - the caller retains the guard
88	    /// and can perform additional operations if needed.
89	    ///
90	    /// Returns the commit hash on success.
91	    pub fn vvcc_commit(&self, args: &vvcc_CommitArgs, output: &mut vvco_Output) -> Result<String, String> {
92	        zvvcc_run_commit_workflow(args, output)
93	    }
94	}
95	
96	impl Drop for vvcc_CommitLock {
97	    fn drop(&mut self) {
98	        zvvcc_release_lock();
99	    }
100	}
101	
102	/// Acquire the commit lock using git update-ref
103	fn zvvcc_acquire_lock() -> Result<(), String> {
104	    let head_output = crate::vvce_git_command(&["rev-parse", "HEAD"])
105	        .output()
106	        .map_err(|e| format!("Failed to run git rev-parse: {}", e))?;
107	
108	    let lock_value = if head_output.status.success() {
109	        String::from_utf8_lossy(&head_output.stdout).trim().to_string()
110	    } else {
111	        "0000000000000000000000000000000000000000".to_string()
112	    };
113	
114	    let result = crate::vvce_git_command(&["update-ref", VVCC_LOCK_REF, &lock_value, ""])
115	        .output()
116	        .map_err(|e| format!("Failed to run git update-ref: {}", e))?;
117	
118	    if result.status.success() {
119	        Ok(())
120	    } else {
121	        Err("Another commit in progress - lock held".to_string())
122	    }
123	}
124	
125	/// Release the commit lock
126	fn zvvcc_release_lock() {
127	    let _ = crate::vvce_git_command(&["update-ref", "-d", VVCC_LOCK_REF])
128	        .output();
129	}
130	
131	/// Stage all changes including untracked files with 'git add -A'
132	fn zvvcc_stage_changes() -> Result<(), String> {
133	    let result = crate::vvce_git_command(&["add", "-A"])
134	        .output()
135	        .map_err(|e| format!("Failed to run git add: {}", e))?;
136	
137	    if result.status.success() {
138	        Ok(())
139	    } else {
140	        Err(format!(
141	            "git add -A failed: {}",
142	            String::from_utf8_lossy(&result.stderr)
143	        ))
144	    }
145	}
146	
147	/// Check if there are staged changes
148	fn zvvcc_has_staged_changes() -> Result<bool, String> {
149	    let result = crate::vvce_git_command(&["diff", "--cached", "--quiet"])
150	        .output()
151	        .map_err(|e| format!("Failed to run git diff: {}", e))?;
152	
153	    Ok(!result.status.success())
154	}
155	
156	/// Run size guard check on staged content
157	fn zvvcc_run_guard(args: &vvcc_CommitArgs, output: &mut vvco_Output) -> Result<(), String> {
158	    let guard_args = vvcg_guard::vvcg_GuardArgs {
159	        limit: args.size_limit,
160	        warn: args.warn_limit,
161	    };
162	
163	    let result = vvcg_guard::vvcg_run(&guard_args, None, output);
164	
165	    match result {
166	        0 => Ok(()),
167	        1 => Err("Staged content exceeds size limit".to_string()),
168	        2 => {
169	            vvco_err!(output, "commit: WARNING - staged content near size limit");
170	            Ok(())
171	        }
172	        _ => Err(format!("Guard returned unexpected code: {}", result)),
173	    }
174	}
175	
176	/// Get the staged diff for commit message generation
177	fn zvvcc_get_staged_diff() -> Result<String, String> {
178	    let output = crate::vvce_git_command(&["diff", "--cached"])
179	        .output()
180	        .map_err(|e| format!("Failed to run git diff: {}", e))?;
181	
182	    if !output.status.success() {
183	        return Err("git diff --cached failed".to_string());
184	    }
185	
186	    Ok(String::from_utf8_lossy(&output.stdout).to_string())
187	}
188	
189	/// Generate commit message using claude CLI
190	fn zvvcc_generate_message_with_claude(diff: &str) -> Result<String, String> {
191	    let prompt = format!(
192	        "Generate a concise commit message for this diff:\n\n<diff>\n{}\n</diff>\n\nRespond with only the commit message, no explanation.",
193	        diff
194	    );
195	
196	    let output = crate::vvce_claude_command()
197	        .args([
198	            "--print",
199	            "--system-prompt",
200	            "Output only a conventional git commit message. No explanation or commentary. Do not wrap in markdown code blocks.",
201	            "--model",
202	            "haiku",
203	            "--no-session-persistence",
204	            &prompt,
205	        ])
206	        .output()
207	        .map_err(|e| format!("Failed to invoke claude: {}", e))?;
208	
209	    if !output.status.success() {
210	        let stderr = String::from_utf8_lossy(&output.stderr);
211	        return Err(format!("claude --print failed: {}", stderr));
212	    }
213	
214	    let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
215	
216	    // Strip markdown code blocks if Claude wrapped the response
217	    let message = if message.starts_with("```") {
218	        let after_opening = message.find('\n').map(|i| i + 1).unwrap_or(0);
219	        let before_closing = message.rfind("```").unwrap_or(message.len());
220	        if before_closing > after_opening {
221	            message[after_opening..before_closing].trim().to_string()
222	        } else {
223	            message
224	        }
225	    } else {
226	        message
227	    };
228	
229	    // Strip Co-Authored-By trailer if Claude CLI added it from global settings
230	    let message: String = message
231	        .lines()
232	        .filter(|line| !line.starts_with("Co-Authored-By:"))
233	        .collect::<Vec<_>>()
234	        .join("\n")
235	        .trim()
236	        .to_string();
237	
238	    if message.is_empty() {
239	        return Err("claude returned empty message".to_string());
240	    }
241	
242	    Ok(message)
243	}
244	
245	/// Format the full commit message with prefix and co-author
246	fn zvvcc_format_commit_message(prefix: Option<&str>, message: &str) -> String {
247	    let mut full_message = String::new();
248	
249	    if let Some(p) = prefix {
250	        full_message.push_str(p);
251	    }
252	
253	    full_message.push_str(message);
254	
255	    full_message
256	}
257	
258	/// Execute the git commit
259	fn zvvcc_execute_commit(message: &str, allow_empty: bool) -> Result<String, String> {
260	    let mut args = vec!["commit", "-m", message];
261	
262	    if allow_empty {
263	        args.push("--allow-empty");
264	    }
265	
266	    let output = crate::vvce_git_command(&args)
267	        .output()
268	        .map_err(|e| format!("Failed to run git commit: {}", e))?;
269	
270	    if !output.status.success() {
271	        let stderr = String::from_utf8_lossy(&output.stderr);
272	        return Err(format!("git commit failed: {}", stderr));
273	    }
274	
275	    let hash_output = crate::vvce_git_command(&["rev-parse", "HEAD"])
276	        .output()
277	        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
278	
279	    if !hash_output.status.success() {
280	        return Err("Failed to retrieve commit hash".to_string());
281	    }
282	
283	    Ok(String::from_utf8_lossy(&hash_output.stdout)
284	        .trim()
285	        .to_string())
286	}
287	
288	/// Run the commit workflow.
289	///
290	/// Returns exit code: 0 for success, 1 for failure.
291	/// On success, prints commit hash to stdout.
292	///
293	/// This is the simple API that acquires and releases the lock automatically.
294	/// For operations that need to hold the lock across multiple steps, use
295	/// `vvcc_CommitLock::vvcc_acquire()` instead.
296	pub fn vvcc_run(args: &vvcc_CommitArgs, output: &mut vvco_Output) -> i32 {
297	    let lock = match vvcc_CommitLock::vvcc_acquire() {
298	        Ok(l) => l,
299	        Err(e) => {
300	            vvco_err!(output, "commit: error: {}", e);
301	            return 1;
302	        }
303	    };
304	
305	    match lock.vvcc_commit(args, output) {
306	        Ok(hash) => {
307	            vvco_out!(output, "{}", hash);
308	            0
309	        }
310	        Err(e) => {
311	            vvco_err!(output, "commit: error: {}", e);
312	            1
313	        }
314	    }
315	    // lock dropped here, releasing the git ref lock
316	}
317	
318	/// Inner workflow that can return Result for cleaner error handling
319	fn zvvcc_run_commit_workflow(args: &vvcc_CommitArgs, output: &mut vvco_Output) -> Result<String, String> {
320	    if !args.no_stage {
321	        zvvcc_stage_changes()?;
322	    }
323	
324	    if !args.allow_empty && !zvvcc_has_staged_changes()? {
325	        return Err("Nothing to commit".to_string());
326	    }
327	
328	    zvvcc_run_guard(args, output)?;
329	
330	    let message = match &args.message {
331	        Some(m) => m.clone(),
332	        None => {
333	            let diff = zvvcc_get_staged_diff()?;
334	            if diff.is_empty() && !args.allow_empty {
335	                return Err("No diff to generate message from".to_string());
336	            }
337	            zvvcc_generate_message_with_claude(&diff)?
338	        }
339	    };
340	
341	    let full_message = zvvcc_format_commit_message(args.prefix.as_deref(), &message);
342	
343	    zvvcc_execute_commit(&full_message, args.allow_empty)
344	}
